        merged[ts] = tok  # last one wins
    merged_sorted = sorted(merged.items())  # (ts, tok) list

    # Format back to string
    merged_str = format_series(merged_sorted)

    # Parse again and return entry count
    final_entries = parse_series(merged_str)
